UNPATCHED CdAddAllocationFromDirent pseudocode (0x1c000a46c):

  int32_t CdAddAllocationFromDirent(int64_t arg1, void* arg2, int32_t arg3, int64_t arg4, void* arg5)
  {
      uint64_t rax = *(arg2 + 0x108);        // current array capacity
      uint64_t rbp = arg3;                    // current dirent index
      uint128_t* rsi;

      if (arg3 < rax)
          rsi = *(arg2 + 0x110);              // existing array is big enough
      else
      {
          uint32_t rax_2 = (rax * 5) << 4;   // *** 32-BIT OVERFLOW *** allocation size = capacity * 0x50
          uint128_t* rax_3 = ExAllocatePoolWithTag(0x11, rax_2, 0x616d6443);  // allocates TRUNCATED size
          rsi = rax_3;
          memset(rax_3, 0, rax_2);           // memset also uses truncated size (safe)
          memmove(rsi, *(arg2 + 0x110), *(arg2 + 0x108) * 0x28);  // *** 64-BIT, NO OVERFLOW *** copies FULL capacity*0x28 bytes → POOL OVERFLOW
          ...
          *(arg2 + 0x108) = rax_4 * 2;       // capacity doubles
      }
      ...
  }

